  const BAZI_DAY_MASTERS = [
    { id: 0, name: '甲木', symbol: '🌳', short: '参天大树，倔强不屈', deep: '【日主：甲木】\n你的命元是甲木，代表参天大树。在你的潜意识深处，有着一种极强的向上的原始驱动力。你性格刚直，有着极高的道德感和原则性。然而，过刚易折，你的灵魂课题是学习“妥协的艺术”。在感情中，你往往是撑起一片天的那个人，但也容易因为过于强势而让伴侣感到压力。\n\n【财运格局】\n你的财富密码在于“扎根”。你不适合赚快钱，你需要在一个领域深耕3到5年，当你的根系足够发达时，财富会呈现爆炸式增长。\n\n【前世业力与今生课题】\n前世的你可能是一位将军或领袖，背负了太多的责任。今生你需要学会的是：允许自己脆弱，允许别人来照顾你。' },
    { id: 1, name: '乙木', symbol: '🌿', short: '藤蔓花草，柔韧圆融', deep: '【日主：乙木】\n你的命元是乙木，代表藤蔓花草。你的生存能力极强，擅长以柔克刚，借力打力。你的灵魂充满了同理心和艺术直觉。你的课题是“边界感”。因为太容易共情他人，你经常会消耗自己的能量。\n\n【财运格局】\n你的财富密码是“人脉圈层”。通过缠绕更高的树木（贵人），你可以轻松攀登到财富的顶端。你非常适合做连接者、平台或艺术相关的工作。\n\n【前世业力与今生课题】\n前世的你可能是一个和平主义者或医者。今生你需要学会的课题是：在爱别人之前，先学会狠狠地爱自己。' },
    { id: 2, name: '丙火', symbol: '☀️', short: '初升太阳，光芒万丈', deep: '【日主：丙火】\n你的命元是丙火，如同天上的太阳。你天生自带光芒，热情、慷慨、充满感染力。你习惯于照亮别人，是人群中的绝对核心。但太阳也有落山的时候，你的内心偶尔会感到一种深刻的孤独。\n\n【财运格局】\n你的财富来源于“影响力”。你越是无私地分享、展现自己，财富就越容易被你吸引。你不适合做幕后工作，你需要站在舞台中央。\n\n【前世业力与今生课题】\n前世的你可能是一位精神导师或祭司。今生你的课题是：接受自己的阴暗面。太阳不需要永远普照大地，你也有悲伤和索取的权利。' },
    { id: 3, name: '丁火', symbol: '🕯️', short: '人间星火，细腻敏锐', deep: '【日主：丁火】\n你的命元是丁火，代表蜡烛、星光。与丙火的张扬不同，你的能量是内敛、细腻、深邃的。你的直觉极准，善于洞察人心最微妙的变化。你是天生的心理学家。\n\n【财运格局】\n你的财富来源于“精尖”。你适合在某个细分领域做到极致，靠专业技能或独特的眼光变现。不要追求大而全，小而美才是你的王道。\n\n【前世业力与今生课题】\n前世的你可能是一位占星师或密教徒。今生的课题是：燃烧自己时，也要学会保护火种。不要为了照亮别人而耗尽自己。' },
    { id: 4, name: '戊土', symbol: '⛰️', short: '高山岩石，沉稳厚重', deep: '【日主：戊土】\n你的命元是戊土，代表高山和大地。你极其靠谱、稳重，是所有人眼里的定海神针。你承载了太多人的期望，但你内心的情绪很难向外流露，容易积压成巨大的压力。\n\n【财运格局】\n戊土的财富密码是“囤积与资产”。你对实业、不动产或长期稳定的复利投资有天然的直觉。你是一座宝藏，需要时间去开采。\n\n【前世业力与今生课题】\n前世的你可能是一位守护者或城主。今生你需要学会的是：学会流动。山也需要水的滋润，允许自己偶尔疯狂、偶尔失控。' },
    { id: 5, name: '己土', symbol: '🌾', short: '田园之土，包容滋养', deep: '【日主：己土】\n你的命元是己土，代表田园、花盆里的泥土。你极具包容心，有着强烈的母性能量。你总是擅长滋养他人，让别人在你身边感到舒服和安全。但你很容易失去自我。\n\n【财运格局】\n你的财富来源于“培育”。你非常适合做教育、服务、疗愈或培训相关的行业。当别人因为你而成长，你的财富也会水涨船高。\n\n【前世业力与今生课题】\n前世的你可能是一位母亲或农夫，一生都在付出。今生的课题是：设定底线。你要明白，不是所有的种子都值得你用生命去灌溉。' },
    { id: 6, name: '庚金', symbol: '⚔️', short: '刀剑利器，刚毅果决', deep: '【日主：庚金】\n你的命元是庚金，代表刀剑和重金属。你自带一种肃杀和果断的能量，爱憎分明，极具正义感。你天生就是来解决问题的，甚至不怕得罪人。\n\n【财运格局】\n你的财富密码是“破局”。你适合在动荡、改革或竞争激烈的环境中杀出一条血路。你的执行力是你最强大的印钞机。\n\n【前世业力与今生课题】\n前世的你可能是一位执法者或侠客。今生你需要学会的课题是：刚柔并济。刀剑虽然锋利，但也容易伤到最亲近的人。' },
    { id: 7, name: '辛金', symbol: '💍', short: '珠玉首饰，精致高贵', deep: '【日主：辛金】\n你的命元是辛金，代表珠宝和首饰。你有着极高的审美，对生活品质要求很高。你外表冷感、内心敏感，甚至有些完美主义。你非常在乎别人对你的评价。\n\n【财运格局】\n辛金的财富来源于“包装与美学”。你适合从事与美、艺术、高价值商品相关的行业。你本身就是一个巨大的IP，你的品味就是你的护城河。\n\n【前世业力与今生课题】\n前世的你可能是一位贵族或艺术家。今生你需要修行的课题是：接受瑕疵。真正的完美，包含对不完美的接纳。' },
    { id: 8, name: '壬水', symbol: '🌊', short: '江河湖海，奔腾不息', deep: '【日主：壬水】\n你的命元是壬水，代表江河湖海。你的心胸像大海一样宽广，聪明、多智、适应能力极强。你讨厌被束缚，喜欢自由奔放的生活。但你有时也会像洪水一样冲动。\n\n【财运格局】\n你的财富密码是“流动与信息”。你适合做贸易、互联网、物流或任何需要快速交换信息的行业。水聚成海，你的财富没有上限。\n\n【前世业力与今生课题】\n前世的你可能是一位航海家或商人。今生你需要学会的是：在狂奔中找到内心的锚。不要因为过于追求自由而失去归属感。' },
    { id: 9, name: '癸水', symbol: '🌧️', short: '雨露之水，润物无声', deep: '【日主：癸水】\n你的命元是癸水，代表雨露和云雾。你是所有日主中最空灵、最富有灵性的。你的直觉和第六感强得可怕，经常能预知事物的走向。你情感细腻，容易悲观。\n\n【财运格局】\n你的财富来源于“无形”。你适合从事玄学、心理学、企划或任何需要极强洞察力的工作。你能看到别人看不到的商机。\n\n【前世业力与今生课题】\n前世的你可能是一位巫师或修行者。今生的课题是：落地。你的灵魂经常漂浮在半空中，你需要通过运动、接触大自然来建立与地球的连接。' }
  ]

  const HD_TYPES = [
    { id: 0, name: '生产者', en: 'Generator', symbol: '🔋', short: '建造世界的基石，荐骨的绝对力量', deep: '【能量类型：生产者】\n你是占据人类70%的生产者。不要觉得普通，你是这个世界真正的引擎。你的核心动力中心（荐骨）是开启不竭能量的钥匙。然而，如果你在做自己不喜欢的事情，你会感到极度的“挫败感”。\n\n【内在权威与策略】\n你的策略是“等待回应”。不要主动发起，而是等待生命把选项带到你面前，然后听从你肚子里的“荐骨声音”（嗯/嗯-嗯）。当你违背荐骨的声音去做事，就是在消耗你的灵魂电量。\n\n【非我主题：挫败感】\n当你感到极度挫败、疲惫、想放弃时，这就是宇宙在提醒你：你走偏了。真正的你，在投入热爱的事物时，是完全不知疲倦的。' },
    { id: 1, name: '显示者', en: 'Manifestor', symbol: '⚡', short: '打破规则的先锋，纯粹的显化力量', deep: '【能量类型：显示者】\n你是极其罕见的显示者（仅占9%）。你是天生的发起人，你的气场是封闭且具有冲击力的。你来这个世界不是为了“工作”，而是为了“发起”。你可以无中生有，将想法瞬间显化。\n\n【内在权威与策略】\n你的策略是“告知”。因为你的能量太强，如果不提前告知身边的人你的决定，他们会本能地阻碍你。告知不是为了请求许可，而是为了清除你前进道路上的障碍。\n\n【非我主题：愤怒】\n当你感到无比愤怒、觉得周围人都在拖你后腿时，这就是你的“非我”状态。你需要属于自己的绝对空间。' },
    { id: 2, name: '投射者', en: 'Projector', symbol: '👁️', short: '洞察一切的向导，等待被邀请的智者', deep: '【能量类型：投射者】\n你是占据20%的投射者。你不是来做苦力的，你是来指导别人如何更好地使用能量的。你拥有看透他人灵魂深处的天赋，你的气场是聚焦且吸收的。\n\n【内在权威与策略】\n你的策略是“等待被邀请”。如果别人没有主动邀请你，你的建议只会招来反感和拒绝。当你在爱情、事业、重大选择中被正式邀请时，你的才华才能真正绽放。\n\n【非我主题：苦涩】\n当你感到不被认可、觉得“为什么他们都不懂我”时，苦涩感就会吞噬你。学会后退，打磨自己的专业，对的人自然会来邀请你。' },
    { id: 3, name: '反映者', en: 'Reflector', symbol: '🪞', short: '宇宙的镜子，月亮的孩子', deep: '【能量类型：反映者】\n你是最稀有的人类图类型（不到1%）。你没有任何定义好的能量中心。你是一面完美的镜子，反映着你所处环境和社区的健康程度。你的本质就是“变化”。\n\n【内在权威与策略】\n你的策略是“等待完整的月亮周期（28天）”。在做重大决定前，你需要经历整整一个月的沉淀，在不同的环境和人身边感受自己的状态，绝对不能仓促做决定。\n\n【非我主题：失望】\n当你发现周围的环境充满毒性、人们虚伪自私时，你会感到极度的失望。你最大的课题是：找到真正滋养你的环境和社区。' },
    { id: 4, name: '显示生产者', en: 'Manifesting Generator', symbol: '🔥', short: '多线操作的效率大师', deep: '【能量类型：显示生产者】\n你是生产者的一个强大分支，占据人类33%。你同时拥有生产者的“荐骨动力”和显示者的“发起能量”。你极度渴望效率，往往能同时处理多项任务。你最大的特点是“跳步骤”和快速试错。\n\n【内在权威与策略】\n你的策略依然是“等待回应”，但你需要增加一步“告知”。当你的荐骨回应了某个机会后，在行动前告知相关的人，能大幅减少你的阻力。\n\n【非我主题：挫败与愤怒】\n当事情进展太慢、或者别人跟不上你的节奏时，你会同时感受到挫败和愤怒。你的课题是：接受有些步骤是不能跳过的，学会对值得的事物保持耐心。' }
  ]

